f62-edf0-4f64-860d-92ba765dd737","name":"Jornada 21","shortName":"J21","week":21,"round":{"id":"3b808e37-1557-4e62-9fe2-e281df66110e","name":"Regular","type":"table","groups":[]}},"group":null,"venue":{"id":"443481b7-4755-442a-9f30-6fdd273726d4","name":"Estadio Tigo La Huerta"},"homeTeam":{"id":"4f4aa07c-3e10-47ca-be0c-1ceade8f2ed5","teamMaster":null,"name":"Club Libertad","shortName":"Libertad","nickname":"Libertad","displayName":"LIB","image":{"id":"a6e26bb0-e7d5-4d03-aa82-d614f3000c4b","alt":null,"url":"https://statics-maker.llt-services.com/apf/images/2024/06/13/original/82e27fcb-621c-46e4-9e62-21c67384e045-769.png","height":700,"width":700,"identifierProcessed":"82e27fcb-621c-46e4-9e62-21c67384e045-769","thumbnails":{"xsmall":"https://statics-maker.llt-services.com/apf/images/2024/06/13/xsmall/82e27fcb-621c-46e4-9e62-21c67384e045-769.png","xlarge":"https://statics-maker.llt-services.com/apf/images/2024/06/13/xlarge/82e27fcb-621c-46e4-9e62-21c67384e045-769.png"}},"shield":null,"streakGame":null,"ownTeam":true,"slug":"libertad-242","webPageUrl":null,"facebookUrl":null,"twitterUrl":null,"instagramUrl":null,"colorAccent":"#000000","palette":{"10":"#E6E6E6","20":"#B8B8B8","30":"#8A8A8A","40":"#5C5C5C","50":"#2E2E2E","60":"#000000","70":"#000000","80":"#000000","90":"#000000","100":"#000000"},"about":"<p style="text-align: justify;">Entre estos italianos hinchas del nuevo Club Libertad había dos muy característicos e históricos: Angelo Gumaressi y Luigi Nuzzarello. Las parcialidades de otros clubes, y hasta los propios hinchas liberteños cuando llegaban a la cancha, exclamaban “ya se siente la presencia de los Gumarelos” refiriéndose a los hinchas albinegros encabezados por Angelo y Luigi. La fusión de ambos apellidos dio origen al mote de Gumarelo, utilizado hasta la actualidad. Un par de años después de aquella histórica fundación, se procede a la mudanza al nuevo predio, donado por la Familia Andreani, ubicado en el barrio Las Mercedes, en donde familias italianas tenían huertas, en las que mayormente se cultivaban varias clases de hortalizas, pero el producto que se destacaba era el Repollo. En ese lugar se ubica hasta hoy en día el Estadio del Club Libertad, denominado en la actualidad Tigo La Huerta.</p>
<p style="text-align: justify;">El primer Campeonato ganado por Libertad fue el torneo de 1.910, apenas 5 años después de su fundación. Luego vendrían 5 títulos más, 1917, 1920, 1930, 1943, 1945. Durante este torneo ganado, Libertad comenzó a armar un poderoso equipo, integrado por muchos jugadores surgidos y formados en el Club, entre ellos Eulogio Kokito Martínez, que tuvo una década prodigiosa, logrando resultados históricos a nivel nacional e internacional, hasta llegar a la obtención del campeonato del año 1955. Este equipo posteriormente fue bautizado como el Equipo del Siglo. El hincha Gumarelo tuvo que esperar 21 años para volver a gritar campeón en el año 1976. Y otra larga espera tuvimos que vivir hasta el comienzo de la era dorada del club Libertad. En el año 2002 se iniciaba un periodo en el que el Gumarelo gritaría campeón en 15 oportunidades. En este periodo se darían un par de Bicampeonatos, 2002-2003 y Apertura 2014/Clausura 2014, y el histórico tetracampeonato (2006, 2007, Apertura 2008 y Clausura 2008). Los campeonatos logrados en el Clausura 2010, Clausura 2012, Apertura 2016, Apertura 2017, Apertura 2021 y Apertura 2022, más la Copa Paraguay 2019, son parte del resurgir liberteño en los últimos 20 años, en el que se apuntan además récord de puntos en los campeonatos logrados en el Apertura 2008 y Apertura 2022, más la presencia ininterrumpida en competencias internacionales que ha situado a la institución como un Club importante y de renombre a nivel continental. A lo largo de su historia, Libertad se ha caracterizado por la formación de jugadores, muchos de ellos luego figuras del futbol mundial y protagonistas de la Selección Nacional.</p>","ticketsUrl":null,"storeUrl":null,"bets":null,"isClickable":true},"awayTeam":{"id":"ea3730f0-23e1-4a2c-b6e1-6fcb3fe5dcd4","teamMaster":null,"name":"Club 2 de Mayo","shortName":"2 de Mayo","nickname":"2 de Mayo","displayName":"2MY","image":{"id":"a5fb9ac5-afbb-4380-9809-621a83121a7e","alt":null,"url":"https:/